$procs = Get-CimInstance Win32_Process -Filter "Name='Unity.exe'"
if ($procs -eq $null) {
    Write-Host "NO_UNITY_PROCESSES"
    exit 0
}
foreach ($p in $procs) {
    Write-Host ("PID=" + $p.ProcessId)
    if ($p.CommandLine -match "RunHotUpdatePipeline") {
        Write-Host ("FOUND_PIPELINE_PID=" + $p.ProcessId)
    }
}

$p = Get-CimInstance Win32_Process -Filter "ProcessId=15048"
if ($p -ne $null) {
    Write-Host "CommandLine: " $p.CommandLine
    if ($p.CommandLine -match "RunHotUpdatePipeline") {
        Write-Host "RESULT=HAS_PIPELINE"
    } else {
        Write-Host "RESULT=NO_PIPELINE"
    }
} else {
    Write-Host "RESULT=NOT_FOUND"
}

$procs = Get-CimInstance Win32_Process -Filter "Name='Unity.exe'"
$foundPipeline = $false
foreach ($p in $procs) {
    Write-Host ("Unity PID=" + $p.ProcessId + " CL=" + $p.CommandLine)
    if ($p.CommandLine -match "RunHotUpdatePipeline") {
        $foundPipeline = $true
        Write-Host "FOUND_PIPELINE_RUNNING"
    }
}
if (-not $foundPipeline) {
    Write-Host "NO_PIPELINE_RUNNING"
}
